content.problemStatement:
What will be the output of the following C++ program?

```cpp
#include 
using namespace std;

class MathOperations {
public:
    // Function to multiply two integers
    int multiply(int a, int b) {
        return a * b;
    }

    // Function to multiply three integers
    int multiply(int a, int b, int c) {
        return a * b * c;
    }

    // Function to multiply a double and an integer
    double multiply(double a, int b) {
        return a * b;
    }

    // Function to multiply two doubles
    double multiply(double a, double b) {
        return a * b;
    }
};

int main() {
    MathOperations math;

    // Testing function overloading
    cout << "Multiply two integers: " << math.multiply(4, 5) << endl;
    cout << "Multiply three integers: " << math.multiply(2, 3, 4) << endl;
    cout << "Multiply a double and an integer: " << math.multiply(2.5, 4) << endl;
    cout << "Multiply two doubles: " << math.multiply(2.5, 3.5) << endl;

    return 0;
}
```

